const data = $input.first().json;

const blockingMap = {
  NOT_SOUNDCLOUD_LINK: 'Submit a valid SoundCloud track URL (must include soundcloud.com).',
  MISSING_REFERENCE_ARTISTS:
    'Add at least one reference artist so we can match you to the right labels.',
};

const issues = (data.audit_flags || [])
  .filter((flag) => blockingMap[flag])
  .map((flag) => blockingMap[flag]);

const issueHtml = issues.length
  ? `<ul>${issues.map((issue) => `<li>${issue}</li>`).join('')}</ul>`
  : '<p>One or more required fields failed validation.</p>';

const html = [
  `<p>Hi ${data.artist_name || 'there'},</p>`,
  '<p>We could not start your LabelScout pitch audit yet. Please fix the following and resubmit:</p>',
  issueHtml,
  '<p>Once updated, submit again at <a href="https://www.labelscoutai.com">labelscoutai.com</a>.</p>',
  `<p style="color:#666;font-size:12px;">Reference: ${data.report_id || 'N/A'}</p>`,
  '<p>— LabelScout</p>',
].join('\n');

return [
  {
    json: {
      ...data,
      email_to: data.contact_email,
      email_subject: 'LabelScout: please fix your submission',
      email_html: html,
      phase: 'phase-01-error-email',
    },
  },
];
